# Make sure we have at least 930 total (need ~425 unique after ~55% dedup)
# Ensure we have enough words to find 425 unique after dedup
assert len(NEW_WORDS) >= 590, f"Only {len(NEW_WORDS)} words provided, need at least 590"

def main():
    with open(FILE, 'r', encoding='utf-8') as f:
        data = json.load(f)

    existing_words = data['words']
    existing_word_set = {w['word'].lower() for w in existing_words}
    existing_ids = {w['id'] for w in existing_words}

    print(f"Current word count: {len(existing_words)}")
    print(f"Existing IDs: {min(existing_ids)} ... {max(existing_ids)}")

    last_id_num = 0
    for wid in existing_ids:
        num = int(wid.split('_')[1])
        last_id_num = max(last_id_num, num)
    print(f"Last ID number: {last_id_num}")

    to_add = []
    skipped = []
    for w in NEW_WORDS:
        if w['word'].lower() in existing_word_set:
            skipped.append(w['word'])
            continue
        to_add.append(w)

    print(f"\nUnique new words available: {len(to_add)}")
    print(f"Skipped (already exist): {len(skipped)}")

    if len(to_add) < 425:
        print(f"ERROR: Only have {len(to_add)} unique new words, need 425!")
        return

    to_add = to_add[:425]
    for i, w in enumerate(to_add):
        w['id'] = f"Kaoyan_{last_id_num + 1 + i:04d}"
        w.setdefault('rootAffix', '')
        w.setdefault('synonyms', [])
        w.setdefault('antonyms', [])

    existing_words.extend(to_add)

    output = {
        "courseID": "Kaoyan",
        "courseName": "иҖғз ”иҜҚжұҮ",
        "words": existing_words
    }

    with open(FILE, 'w', encoding='utf-8') as f:
        json.dump(output, f, ensure_ascii=False, indent=2)

    print(f"\nAdded {len(to_add)} words successfully!")
    print(f"New total: {len(existing_words)}")
    print(f"First new ID: {to_add[0]['id']} -> {to_add[0]['word']}")
    print(f"Last new ID: {to_add[-1]['id']} -> {to_add[-1]['word']}")

    with open(FILE, 'r', encoding='utf-8') as f:
        verify = json.load(f)
    print(f"\nVerification: {len(verify['words'])} total words in file.")

if __name__ == '__main__':
    main()
